-- ----------------------------------------------------------------------------
-- vw_users: Dev-login identities for the demo app. Email is the PK.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_users WITH (security_invoker = ON) AS
SELECT
  calc_users_name(t.users_id) AS name,                                          -- PK = Email
  t.users_id,                                                                   -- Synthetic PK = Email.
  t.email,                                                                      -- Login email (PK source).
  t.first_name,                                                                 -- Given name.
  t.last_name,                                                                  -- Family name.
  t.role,                                                                       -- admin or viewer.
  calc_users_full_name(t.users_id) AS full_name                                 -- LastName, FirstName.
FROM users t;

-- ----------------------------------------------------------------------------
-- vw_customers: A CRM contact. Email is the PK.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_customers WITH (security_invoker = ON) AS
SELECT
  calc_customers_name(t.customers_id) AS name,                                  -- PK = Email
  t.customers_id,                                                               -- Synthetic PK = Email.
  t.email,                                                                      -- Customer email (PK source).
  t.first_name,                                                                 -- Given name.
  t.last_name,                                                                  -- Family name.
  calc_customers_full_name(t.customers_id) AS full_name,                        -- LastName, FirstName.
  calc_customers_lifetime_sales(t.customers_id) AS lifetime_sales,              -- Sum of this customer's order totals from the last 60 days (orders older than 60 days do not count).
  calc_customers_unpaid_order_count(t.customers_id) AS unpaid_order_count,      -- Number of this customer's orders that are not yet paid in full.
  calc_customers_large_order_count(t.customers_id) AS large_order_count,        -- Number of this customer's orders with a Total over $500. SUMIFS expression-mode workaround: agg_range yields 1 per row, then a real WHERE clause filters via the operator criterion ">500" (Program.cs ExtractCriteriaOp, supported on SUMIFS but not yet on COUNTIFS).
  calc_customers_is_vip(t.customers_id) AS is_vip                               -- True when LifetimeSales > 1000 AND the customer has at most 1 unpaid order.
FROM customers t;

-- ----------------------------------------------------------------------------
-- vw_orders: A customer order. OrderNumber is the PK.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_orders WITH (security_invoker = ON) AS
SELECT
  calc_orders_name(t.orders_id) AS name,                                        -- PK = OrderNumber
  t.orders_id,                                                                  -- Synthetic PK = OrderNumber.
  t.order_number,                                                               -- Human-readable order number (PK source).
  t.order_date,                                                                 -- Date the order was placed.
  t.customer,                                                                   -- FK -> Customers.Name (the customer's email).
  calc_orders_customer_first_name(t.orders_id) AS customer_first_name,          -- Customer's first name, looked up via Customer FK.
  calc_orders_customer_last_name(t.orders_id) AS customer_last_name,            -- Customer's last name, looked up via Customer FK.
  calc_orders_customer_full_name(t.orders_id) AS customer_full_name,            -- Customer's full name, looked up via Customer FK.
  calc_orders_customer_email(t.orders_id) AS customer_email,                    -- Customer's email, looked up via Customer FK.
  t.total,                                                                      -- Order total in dollars.
  calc_orders_amount_paid(t.orders_id) AS amount_paid,                          -- Sum of all payments recorded against this order.
  calc_orders_balance(t.orders_id) AS balance,                                  -- Outstanding balance: Total - AmountPaid.
  calc_orders_is_paid(t.orders_id) AS is_paid,                                  -- True when Balance <= 0.
  calc_orders_unpaid_flag(t.orders_id) AS unpaid_flag,                          -- 1 when the order is unpaid, 0 otherwise — summed by Customers.UnpaidOrderCount.
  calc_orders_is_recent(t.orders_id) AS is_recent,                              -- True when OrderDate is within the last 60 days. Drives the 60-day window on Customers.LifetimeSales.
  calc_orders_recent_total(t.orders_id) AS recent_total,                        -- Total if the order is recent, 0 otherwise — summed by Customers.LifetimeSales.
  calc_orders_fcs_subtotal(t.orders_id) AS fcs_subtotal,                        -- Sum of LineTotal across this order's FCS line items (in $M).
  calc_orders_fcs_unit_count(t.orders_id) AS fcs_unit_count                     -- Total FCS units shipped on this order.
FROM orders t;

-- ----------------------------------------------------------------------------
-- vw_payments: A payment recorded against an order. PaymentNumber is the PK.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_payments WITH (security_invoker = ON) AS
SELECT
  calc_payments_name(t.payments_id) AS name,                                    -- PK = PaymentNumber
  t.payments_id,                                                                -- Synthetic PK = PaymentNumber.
  t.payment_number,                                                             -- Human-readable payment number (PK source).
  t.order_id,                                                                   -- FK -> Orders.Name (the order number).
  t.payment_date,                                                               -- Date the payment was received.
  t.amount,                                                                     -- Payment amount in dollars.
  t.method,                                                                     -- Payment method: card, check, cash, wire, ach.
  calc_payments_order_number(t.payments_id) AS order_number,                    -- Parent order's human-readable number.
  calc_payments_order_date(t.payments_id) AS order_date,                        -- Parent order's date.
  calc_payments_order_total(t.payments_id) AS order_total,                      -- Parent order's total.
  calc_payments_order_amount_paid(t.payments_id) AS order_amount_paid,          -- Parent order's total paid (across all its payments).
  calc_payments_order_balance(t.payments_id) AS order_balance,                  -- Parent order's outstanding balance.
  calc_payments_order_is_paid(t.payments_id) AS order_is_paid,                  -- Parent order's paid-in-full flag.
  calc_payments_order_customer(t.payments_id) AS order_customer,                -- Parent order's customer FK (email).
  calc_payments_customer_full_name(t.payments_id) AS customer_full_name,        -- Parent order's customer full name (two-hop).
  calc_payments_customer_email(t.payments_id) AS customer_email                 -- Parent order's customer email (two-hop).
FROM payments t;

-- ----------------------------------------------------------------------------
-- vw_jet_models: Catalog of fighter-jet airframes that flight-control systems are built for. ModelCode is the PK.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_jet_models WITH (security_invoker = ON) AS
SELECT
  calc_jet_models_name(t.jet_models_id) AS name,                                -- PK = ModelCode
  t.jet_models_id,                                                              -- Synthetic PK = ModelCode.
  t.model_code,                                                                 -- Short model designation, e.g. F-16C.
  t.manufacturer,                                                               -- Airframe OEM.
  t.generation,                                                                 -- Fighter generation (4, 4.5, 5).
  calc_jet_models_is_fifth_gen(t.jet_models_id) AS is_fifth_gen,                -- True for 5th-generation airframes (stealth-era).
  calc_jet_models_fcs_variant_count(t.jet_models_id) AS fcs_variant_count,      -- Number of distinct FCS variants offered for this airframe.
  calc_jet_models_total_units_ordered(t.jet_models_id) AS total_units_ordered,  -- Total FCS units ordered across all variants for this airframe.
  calc_jet_models_total_revenue(t.jet_models_id) AS total_revenue               -- Total FCS revenue (in $M) across all variants for this airframe.
FROM jet_models t;

-- ----------------------------------------------------------------------------
-- vw_flight_control_systems: Flight-control-system product variants. Each variant targets one jet model with a specific control architecture and redundancy level. FCSCode is the PK.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_flight_control_systems WITH (security_invoker = ON) AS
SELECT
  calc_flight_control_systems_name(t.flight_control_systems_id) AS name,        -- PK = FCSCode
  t.flight_control_systems_id,                                                  -- Synthetic PK = FCSCode.
  t.fcs_code,                                                                   -- Product code, e.g. FCS-F35-FBW4.
  t.jet_model_id,                                                               -- FK -> JetModels.Name.
  calc_flight_control_systems_jet_manufacturer(t.flight_control_systems_id) AS jet_manufacturer,-- Airframe manufacturer, via JetModelId.
  calc_flight_control_systems_jet_generation(t.flight_control_systems_id) AS jet_generation,-- Airframe generation, via JetModelId.
  t.architecture,                                                               -- Control architecture: fly-by-wire, fly-by-light, analog-hybrid.
  t.redundancy_channels,                                                        -- Number of independent control channels (2, 3, or 4).
  t.unit_price,                                                                 -- Per-unit price in $M USD.
  calc_flight_control_systems_is_triple_redundant(t.flight_control_systems_id) AS is_triple_redundant,-- True when RedundancyChannels >= 3 (meets typical fighter airworthiness floor).
  calc_flight_control_systems_is_quad_redundant(t.flight_control_systems_id) AS is_quad_redundant,-- True when RedundancyChannels >= 4 (5th-gen / carrier-grade).
  calc_flight_control_systems_meets_fifth_gen_spec(t.flight_control_systems_id) AS meets_fifth_gen_spec,-- Quad-redundant fly-by-wire or fly-by-light on a 5th-gen airframe.
  calc_flight_control_systems_total_units_ordered(t.flight_control_systems_id) AS total_units_ordered,-- Sum of order-line quantities across all orders.
  calc_flight_control_systems_total_revenue(t.flight_control_systems_id) AS total_revenue-- Sum of order-line revenue (in $M).
FROM flight_control_systems t;

-- ----------------------------------------------------------------------------
-- vw_order_lines: FCS line items on an order — links Orders to FlightControlSystems with a quantity. LineNumber is the PK.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_order_lines WITH (security_invoker = ON) AS
SELECT
  calc_order_lines_name(t.order_lines_id) AS name,                              -- PK = LineNumber
  t.order_lines_id,                                                             -- Synthetic PK = LineNumber.
  t.line_number,                                                                -- Human-readable line code, e.g. OL-3001.
  t.order_id,                                                                   -- FK -> Orders.Name.
  t.fcs_id,                                                                     -- FK -> FlightControlSystems.Name.
  t.quantity,                                                                   -- Number of FCS units on this line.
  calc_order_lines_fcs_unit_price(t.order_lines_id) AS fcs_unit_price,          -- Per-unit price from the FCS catalog (in $M).
  calc_order_lines_fcs_architecture(t.order_lines_id) AS fcs_architecture,      -- FCS control architecture.
  calc_order_lines_fcs_jet_model(t.order_lines_id) AS fcs_jet_model,            -- Airframe this FCS targets.
  calc_order_lines_fcs_meets_fifth_gen_spec(t.order_lines_id) AS fcs_meets_fifth_gen_spec,-- Whether the FCS meets 5th-gen spec (two-hop calc).
  calc_order_lines_order_number(t.order_lines_id) AS order_number,              -- Parent order number.
  calc_order_lines_order_customer(t.order_lines_id) AS order_customer,          -- Parent order customer FK.
  calc_order_lines_line_total(t.order_lines_id) AS line_total                   -- Quantity * FCSUnitPrice (in $M).
FROM order_lines t;

